import{_ as o,o as d,c as t,a3 as c}from"./chunks/framework.BlfGB29P.js";const g=JSON.parse('{"title":"消息中心 / 通知 / 实时聊天","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/messaging.md","filePath":"cosmos/basic-app/messaging.md","lastUpdated":1783773945000}'),a={name:"cosmos/basic-app/messaging.md"};function i(s,e,n,r,l,p){return d(),t("div",null,[...e[0]||(e[0]=[c(`<h1 id="消息中心-通知-实时聊天" tabindex="-1">消息中心 / 通知 / 实时聊天 <a class="header-anchor" href="#消息中心-通知-实时聊天" aria-label="Permalink to &quot;消息中心 / 通知 / 实时聊天&quot;">​</a></h1><p>XiHan.BasicApp 的消息能力横跨三块：<strong>企业级消息中心（站内通知/公告）</strong>、<strong>多渠道消息投递（邮件/短信/机器人）</strong> 与 <strong>SignalR 实时（通知推送 + 在线聊天）</strong>。它们共享一套模板、偏好门控与发件箱异步机制，源码集中在 <code>modules/XiHan.BasicApp.Saas</code> 的 <code>Application/AppServices/Messaging</code>、<code>Application/Services/Messaging</code>、<code>Domain/DomainServices/Messaging</code>、<code>Domain/Entities</code> 与 <code>Hubs</code> 下。</p><blockquote><p>部署提示：消息中心涉及库表重建（<code>Sys_Notification</code>、<code>Sys_User_Notification</code>、<code>Sys_User_Notification_Preference</code>、聊天四表等）。遵循 BasicApp「部署即重建库、不做向后兼容」约定，异常态一律 fail-closed。</p></blockquote><h2 id="全景" tabindex="-1">全景 <a class="header-anchor" href="#全景" aria-label="Permalink to &quot;全景&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                       发布 / 发送（AppService，[DynamicApi] REST）</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>        ┌────────────────────────────┼────────────────────────────┐</span></span>
<span class="line"><span>        ▼                            ▼                             ▼</span></span>
<span class="line"><span>  站内通知（消息中心）          多渠道扇出                     在线聊天</span></span>
<span class="line"><span>  SysNotification            NotificationFanoutService        ChatAppService</span></span>
<span class="line"><span>   └ 展开 SysUserNotification  ├ 邮箱 → SysEmail  ┐             └ SysChatConversation</span></span>
<span class="line"><span>   └ 偏好门控                  ├ 短信 → SysSms    ├ 发件箱异步       + Member / Message</span></span>
<span class="line"><span>   └ 实时推送 ReceiveNotification└ 机器人 → 直发   ┘（IRedisDelayQueue） + Reaction</span></span>
<span class="line"><span>                                     │                             │</span></span>
<span class="line"><span>                                     ▼                             ▼</span></span>
<span class="line"><span>                              框架 Bot / Messaging 管道       SignalR 实时推送</span></span>
<span class="line"><span>                              （Email/Sms/DingTalk/…）        （ChatRealtimeMethods）</span></span></code></pre></div><p>三条链路都遵循 BasicApp 全局约定：应用服务经 <code>[DynamicApi]</code> 直接暴露 REST（无 Controller），三级权限码门控，响应统一 <code>ApiResponse</code>，时间存 UTC 按 <code>X-Timezone</code> 头换算输出。</p><h2 id="通道与业务类型常量" tabindex="-1">通道与业务类型常量 <a class="header-anchor" href="#通道与业务类型常量" aria-label="Permalink to &quot;通道与业务类型常量&quot;">​</a></h2><p>投递通道用 <code>[Flags]</code> 枚举 <code>MessageChannel</code> 表示，可按位组合：</p><table tabindex="0"><thead><tr><th>值</th><th>枚举</th><th>含义</th></tr></thead><tbody><tr><td>1</td><td><code>SiteNotification</code></td><td>站内通知</td></tr><tr><td>2</td><td><code>Email</code></td><td>邮件</td></tr><tr><td>4</td><td><code>Sms</code></td><td>短信</td></tr><tr><td>8</td><td><code>Bot</code></td><td>机器人</td></tr></tbody></table><p>与框架 Messaging 信封对接的通道字符串集中在 <code>SaasMessageChannelNames</code>（<code>email</code> / <code>sms</code> / <code>bot</code>，其中 bot 仅直发、不入发件箱重放），业务类型集中在 <code>SaasMessageBusinessTypes</code>（如 <code>message.notification</code>），模板编码集中在 <code>SaasMessageTemplateCodes</code>。三者都是<strong>单一事实源</strong>，禁止散落魔法字符串——新增通道/类型/模板码必须在此登记。</p><hr><h2 id="一、企业级消息中心-站内通知" tabindex="-1">一、企业级消息中心（站内通知） <a class="header-anchor" href="#一、企业级消息中心-站内通知" aria-label="Permalink to &quot;一、企业级消息中心（站内通知）&quot;">​</a></h2><p>站内通知采用<strong>内容表 + 投递关系表</strong>分离设计，避免&quot;通知 × 用户&quot;直接笛卡尔积：</p><ul><li><code>SysNotification</code>：一条通知的<strong>内容主表</strong>（正文、发布状态、目标范围、展示分级）。</li><li><code>SysUserNotification</code>：<code>通知 × 用户</code>的<strong>投递关系表</strong>，承载每人的已读/确认/删除状态。</li></ul><h3 id="内容主表关键字段-sysnotification" tabindex="-1">内容主表关键字段（SysNotification） <a class="header-anchor" href="#内容主表关键字段-sysnotification" aria-label="Permalink to &quot;内容主表关键字段（SysNotification）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>分类</td><td><code>NotificationType</code></td><td>五类：<code>System</code>/<code>Security</code>/<code>Business</code>/<code>Todo</code>/<code>Emergency</code>（内容分类，与展示分级正交）</td></tr><tr><td>优先级</td><td><code>Priority</code></td><td><code>Low</code>/<code>Normal</code>/<code>High</code>/<code>Urgent</code>，决定排序权重、紧急置顶、分级推送强度</td></tr><tr><td>正文格式</td><td><code>ContentFormat</code></td><td><code>Text</code>/<code>Markdown</code>/<code>Html</code>，决定前端渲染方式（默认 Markdown，配合 MdEditor）</td></tr><tr><td>富文本</td><td><code>Content</code></td><td>大文本列；<code>Title</code> + <code>Icon</code> + <code>Link</code>（跳转）</td></tr><tr><td>投递渠道</td><td><code>DeliveryChannels</code></td><td><code>MessageChannel</code> 位组合；<strong>必含站内信</strong>，可叠加 邮箱/短信/机器人</td></tr><tr><td>定向</td><td><code>TargetType</code> + <code>TargetValue</code></td><td><code>All</code>/<code>Role</code>/<code>Department</code>/<code>User</code>；非全员时 <code>TargetValue</code> 存目标 ID 数组（JSON）</td></tr><tr><td>强制阅读</td><td><code>IsMandatory</code></td><td>有未读则拦截，须读毕方可进入系统</td></tr><tr><td>顶部横幅</td><td><code>IsBanner</code></td><td>置于页面顶部通知条（系统维护/版本升级等）</td></tr><tr><td>登录弹窗</td><td><code>IsPopup</code></td><td>登录后弹窗，每用户仅弹一次（由 <code>SysUserNotification.PopupShownTime</code> 记录）</td></tr><tr><td>确认</td><td><code>NeedConfirm</code></td><td>可选确认，记录 <code>ConfirmTime</code>，不阻断进入系统</td></tr><tr><td>有效期</td><td><code>StartTime</code> / <code>ExpirationTime</code></td><td>生效区间，到期自动隐藏</td></tr><tr><td>状态</td><td><code>IsPublished</code></td><td><code>false</code>=草稿 / <code>true</code>=已发布（发布后不可编辑/删除）</td></tr></tbody></table><p><code>NotificationType</code>（五类分类）与 <code>NotificationPriority</code>（四级优先级）<strong>正交</strong>：分类用于按类筛选/图标着色，优先级决定强提醒；同一条紧急停服公告可以是 <code>Emergency</code> 类 + <code>Urgent</code> 级 + 顶部横幅 + 强制阅读。</p><h3 id="投递关系表关键字段-sysusernotification" tabindex="-1">投递关系表关键字段（SysUserNotification） <a class="header-anchor" href="#投递关系表关键字段-sysusernotification" aria-label="Permalink to &quot;投递关系表关键字段（SysUserNotification）&quot;">​</a></h3><ul><li><code>NotificationStatus</code>：<code>Unread</code>/<code>Read</code>/<code>Deleted</code>；<code>Deleted</code> 为预留状态位（查询侧已按其过滤），但当前 <code>UserInboxAppService</code>/<code>UserInboxDomainService</code> 尚未暴露&quot;删除消息&quot;的写入端点，也没有配套的物理清理定时任务——用户侧删除消息能力暂未接线。</li><li><code>ReadTime</code> / <code>ConfirmTime</code> / <code>PopupShownTime</code>：分别记录已读、确认、弹窗已展示时间。</li><li>唯一约束 <code>(TenantId, NotificationId, UserId)</code>；未读计数与消息中心列表各有覆盖索引。</li></ul><h3 id="发布-→-展开-→-门控-→-推送" tabindex="-1">发布 → 展开 → 门控 → 推送 <a class="header-anchor" href="#发布-→-展开-→-门控-→-推送" aria-label="Permalink to &quot;发布 → 展开 → 门控 → 推送&quot;">​</a></h3><p>发布走 <code>NotificationAppService.PublishNotificationAsync</code>（<code>[UnitOfWork(true)]</code> + 权限码 <code>SaasPermissionCodes.Message.Publish</code>），一个事务内完成：</p><ol><li><strong>展开</strong>：<code>NotificationDomainService</code> 按 <code>TargetType</code> 解析收件人（All/Role/Department/User），批量 <code>INSERT</code> <code>SysUserNotification</code> 行。</li><li><strong>偏好门控</strong>：站内信落行前经 <code>FilterByPreferenceAsync</code> 过滤（见下节）；<strong>强制阅读 / 紧急通知一律送达，不受门控</strong>。</li><li><strong>多渠道扇出</strong>：<code>NotificationFanoutService.FanoutAsync</code> 按 <code>DeliveryChannels</code> 落邮箱/短信行、调度机器人广播（见下节，与发布同事务保证原子一致）。</li><li><strong>实时推送</strong>：提交后调 <code>IRealtimeNotificationService&lt;BasicAppNotificationHub&gt;</code> 推 <code>ReceiveNotification</code>——全员目标 <code>SendToAllAsync</code>，定向目标 <code>SendToUsersAsync</code>（收件箱即时刷新，无需等下次拉取；推送失败只记日志、不影响发布）。</li></ol><h3 id="运营闭环-发-n-读-m-未读人员-催办" tabindex="-1">运营闭环（发 N 读 M / 未读人员 / 催办） <a class="header-anchor" href="#运营闭环-发-n-读-m-未读人员-催办" aria-label="Permalink to &quot;运营闭环（发 N 读 M / 未读人员 / 催办）&quot;">​</a></h3><ul><li><strong>发 N 读 M / 已确认 K</strong>：发布结果返回 <code>RecipientCount</code>；管理侧另有专用统计接口 <code>NotificationQueryService.GetNotificationReadStatsAsync</code>，一次性给出 <code>RecipientCount</code>/<code>ReadCount</code>/<code>UnreadCount</code>/<code>ConfirmCount</code>（按 <code>ConfirmTime</code> 非空统计）+ <code>NeedConfirm</code>，供详情页展示阅读进度。</li><li><strong>未读人员</strong>：<code>GetNotificationUnreadUserPageAsync</code> 按通知 ID 分页查询未读用户（<code>NotificationStatus=Unread</code>），带出 <code>UserName</code>/<code>RealName</code>/<code>ReceivedTime</code>，可经通用导出机制导 CSV。</li><li><strong>催办</strong>：<code>RemindAsync(id)</code> 查出该通知未读用户（<code>NotificationStatus=Unread</code>），对<strong>在线未读者</strong>重新实时推送 <code>ReceiveNotification</code>——<strong>不改库</strong>，仅即时再提醒（同样受权限码 <code>Message.Publish</code> 门控）。</li></ul><h3 id="用户侧-收件箱-api-userinboxappservice" tabindex="-1">用户侧：收件箱 API（UserInboxAppService） <a class="header-anchor" href="#用户侧-收件箱-api-userinboxappservice" aria-label="Permalink to &quot;用户侧：收件箱 API（UserInboxAppService）&quot;">​</a></h3><p>面向登录用户自己的站内信读取，全部方法以当前用户为作用域（<code>[Authorize]</code> 类级）：</p><ul><li>列表 / 未读列表：<code>GetListAsync(unreadOnly)</code>。</li><li>强制阅读拦截：<code>GetMandatoryUnreadAsync()</code>（前端路由守卫据此拦截进入）。</li><li>顶部横幅：<code>GetBannerAsync()</code>；登录弹窗：<code>GetPopupAsync()</code> + <code>MarkPopupShownAsync</code>（保证仅弹一次）。</li><li>已读：<code>MarkReadAsync</code> / <code>MarkAllReadAsync</code>；确认：<code>ConfirmAsync</code>。</li></ul><hr><h2 id="二、消息模板-scriban-渲染" tabindex="-1">二、消息模板（Scriban 渲染） <a class="header-anchor" href="#二、消息模板-scriban-渲染" aria-label="Permalink to &quot;二、消息模板（Scriban 渲染）&quot;">​</a></h2><p><code>SysMessageTemplate</code> 承载<strong>邮件/短信/站内通知</strong>三渠道的内容模板，模板只管&quot;内容如何渲染&quot;，&quot;发给谁/何时发&quot;由投递链路决定。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>TemplateCode</code></td><td>渠道内唯一标识（如 <code>auth-email-login-code</code>）</td></tr><tr><td><code>Channel</code></td><td><code>MessageChannel</code>（站内通知/邮件/短信）</td></tr><tr><td><code>Subject</code></td><td>主题模板（邮件主题/通知标题，短信不使用）</td></tr><tr><td><code>Content</code></td><td>内容模板（Scriban 语法，大文本列）</td></tr><tr><td><code>IsHtml</code></td><td>内容是否 HTML（邮件渠道有效）</td></tr><tr><td><code>Status</code></td><td><code>EnableStatus</code> 启用/停用（停用则查找跳过，回退全局或调用方内置内容）</td></tr></tbody></table><p><strong>渲染引擎</strong>：复用框架 <code>XiHan.Framework.Templating</code>，Scriban 语法。模板正文里的变量占位、条件、循环等写法见框架文档；此处内容里的双花括号占位形如 <code>{{ variable }}</code>。</p><p><strong>租户覆盖默认</strong>：唯一约束 <code>(TenantId, Channel, TemplateCode)</code>；<code>TenantId=0</code> 为平台全局模板（共享读）。发送链路按 <code>(Channel, TemplateCode)</code> 查找，<strong>当前租户模板优先 → 全局兜底</strong>；查找结果走分布式缓存，模板增删改由 <code>MessageTemplateAppService</code> 触发缓存失效（<code>InvalidateMessageTemplateAsync</code>），渲染侧即时可见。</p><p><strong>渲染缺失即回退</strong>：模板不存在/停用/渲染失败时，投递链路保留调用方原始内容继续处理（fail-safe，不阻断发送）。</p><p>种子模板编码见 <code>SaasMessageTemplateCodes</code>，例如认证链路的 <code>auth-email-login-code</code>（登录验证码）、<code>auth-password-reset</code>（找回密码，携一次性重置链接），以及扇出用的 <code>notification-email</code> / <code>notification-sms</code>。</p><hr><h2 id="三、多渠道扇出与异步投递" tabindex="-1">三、多渠道扇出与异步投递 <a class="header-anchor" href="#三、多渠道扇出与异步投递" aria-label="Permalink to &quot;三、多渠道扇出与异步投递&quot;">​</a></h2><h3 id="扇出-一次发布可达四渠道" tabindex="-1">扇出：一次发布可达四渠道 <a class="header-anchor" href="#扇出-一次发布可达四渠道" aria-label="Permalink to &quot;扇出：一次发布可达四渠道&quot;">​</a></h3><p><code>NotificationFanoutService.FanoutAsync</code> 按通知的 <code>DeliveryChannels</code> 逐位处理（站内信已由发布链路落行，此处处理邮箱/短信/机器人）：</p><table tabindex="0"><thead><tr><th>渠道</th><th>收件人解析</th><th>联系方式校验</th><th>落地方式</th></tr></thead><tbody><tr><td>邮箱</td><td>偏好门控 <code>Email</code> 渠道</td><td><code>Email</code> 字段非空</td><td><strong>通知级渲染一次</strong>（<code>notification-email</code>，变量 <code>title</code>/<code>content</code>/<code>brand</code>）后逐用户落 <code>SysEmail</code> 行走发件箱</td></tr><tr><td>短信</td><td>偏好门控 <code>Sms</code> 渠道</td><td><code>Phone</code> 非空 <strong>且 <code>SysUserSecurity.PhoneVerified</code></strong></td><td>逐用户落 <code>SysSms</code> 行；行保留内部模板码 <code>notification-sms</code>，供云厂商 <code>TemplateMap</code> 映射</td></tr><tr><td>机器人</td><td>通知级广播（无用户维度）</td><td>无</td><td>UoW 提交后经 <code>IMessageDispatcher</code> 以 bot 通道<strong>直发</strong></td></tr></tbody></table><p>要点：</p><ul><li><strong>邮箱只渲染一次</strong>：<code>title</code>/<code>content</code>/<code>brand</code> 都是通知级变量、无用户维度，避免逐行重复渲染；模板缺失回退通知纯内容（<code>IsHtml</code> 按通知正文格式）。</li><li><strong>短信 fail-closed</strong>：未验证手机号不可信，一律跳过；<code>Content</code> 为纯文本兜底，云厂商发送须在短信配置 <code>TemplateMap</code> 中登记 <code>notification-sms</code> → 服务商模板码的映射，否则按纯文本尝试。</li><li><strong>机器人不入发件箱</strong>：无用户绑定，仅通知级广播；照 <code>DbMessageOutbox.OnCompleted</code> 先例在 <strong>UoW 提交后</strong>投递，失败仅记日志、不回滚已提交的发布。当前用户偏好里的 <code>ChannelBot</code> 开关留作未来&quot;按用户投递&quot;的门。</li><li><strong>原子一致</strong>：邮箱/短信落行在发布事务内，事务回滚则扇出行一并回滚，保证渠道扇出与站内信原子一致；发送本身由发件箱异步承载，不阻塞发布接口。</li></ul><h3 id="偏好门控-sysusernotificationpreference" tabindex="-1">偏好门控（SysUserNotificationPreference） <a class="header-anchor" href="#偏好门控-sysusernotificationpreference" aria-label="Permalink to &quot;偏好门控（SysUserNotificationPreference）&quot;">​</a></h3><p>每用户 1:1 的通知偏好（与 <code>SysUser</code> 一对一，独立表演进），按<strong>渠道 × 类型</strong>两组布尔开关门控：</p><ul><li>渠道开关：<code>ChannelInApp</code>（默认开）、<code>ChannelEmail</code>（默认开）、<code>ChannelSms</code>（默认关）、<code>ChannelPush</code>（默认开）、<code>ChannelBot</code>（默认关，机器人需用户侧存在可达绑定才有意义）。</li><li>类型开关：<code>TypeAnnouncement</code> / <code>TypeTask</code> / <code>TypeApproval</code> / <code>TypeSecurity</code>（默认开）、<code>TypeMarketing</code>（默认关，营销可随时关闭，GDPR 合规）。个人中心（<code>ProfileAppService</code>）可读写全部五个开关，但当前 <code>NotificationDomainService.FilterByPreferenceAsync</code> 的门控只按 <code>NotificationType</code> 落到三档：<code>Security→TypeSecurity</code>、<code>Todo→TypeTask</code>，其余（<code>System</code>/<code>Business</code>/<code>Emergency</code>）一律落 <code>TypeAnnouncement</code>；<code>TypeApproval</code>/<code>TypeMarketing</code> 目前未接入任何 <code>NotificationType</code> 判定分支，是为未来业务类型预留的偏好位。</li><li>首次读取无记录时由应用层按默认值惰性创建。<strong>强制阅读 / 紧急通知一律送达，不受门控</strong>（安全告警建议始终开启）。</li></ul><h3 id="异步投递-落库-pending-→-发件箱-→-后台消费" tabindex="-1">异步投递：落库 Pending → 发件箱 → 后台消费 <a class="header-anchor" href="#异步投递-落库-pending-→-发件箱-→-后台消费" aria-label="Permalink to &quot;异步投递：落库 Pending → 发件箱 → 后台消费&quot;">​</a></h3><p>邮件/短信统一异步，走业务层发件箱（Redis 延迟队列），不阻塞调用接口：</p><ol><li><code>MessageDeliveryService.CreateEmailAsync</code> / <code>CreateSmsAsync</code>：先渲染模板（若带 <code>TemplateCode</code>），落 <code>SysEmail</code>/<code>SysSms</code> 为 <code>Pending</code>，再 <code>DbMessageOutbox.EnqueueAsync(channel, entityId)</code> 入队（事务提交后才入队，确保 DB 行先可见）。</li><li><code>MessageOutboxHostedService</code>（继承框架 <code>XiHanBackgroundServiceBase</code>）拉取消费：原子领取 <code>TryClaimForSendingAsync</code>（<code>Pending</code>/可重试 <code>Failed</code> → <code>Sending</code>，防重复发送）→ 经 <code>IMessageDispatcher</code> 分发到框架 Bot 管道发送 → 更新 <code>Sent</code>/<code>Failed</code>（失败重试，<code>MaxRetryCount</code> 默认 3）。</li><li><strong>启动恢复</strong>：<code>ResetInFlightAndCollectPendingAsync</code> 把崩溃残留的 <code>Sending</code> 复位为 <code>Pending</code> 并重新收集在途/可重试行入队。</li></ol><p><code>SysEmail</code> 记录承载完整投递语义：<code>EmailStatus</code>（<code>Pending</code>/<code>Sending</code>/<code>Success</code>/<code>Failed</code>/<code>Cancelled</code>）、<code>RetryCount</code>/<code>MaxRetryCount</code>、<code>ErrorMessage</code>、<code>ScheduledTime</code>（定时发送）、<code>BusinessType</code>+<code>BusinessId</code>（关联业务实体）。将状态改回 <code>Pending</code>（<code>MessageAppService.UpdateEmailStatusAsync</code>）会重新入队。</p><blockquote><p>队列/发件箱这套&quot;提交后入队 + 原子领取 + 启动恢复&quot;的模式是 BasicApp 后台异步的通用范式（导出、发件箱等复用），底层为 <code>IRedisDelayQueue&lt;T&gt;</code> + <code>XiHanBackgroundServiceBase</code>，消息路由见框架 <a href="./../framework/packages/messaging">Messaging</a>。</p></blockquote><h3 id="网关配置-全部-store-化-禁-appsettings" tabindex="-1">网关配置（全部 store 化，禁 appsettings） <a class="header-anchor" href="#网关配置-全部-store-化-禁-appsettings" aria-label="Permalink to &quot;网关配置（全部 store 化，禁 appsettings）&quot;">​</a></h3><p>邮件/短信/机器人的网关连接与凭据都存库、由前端配置页维护，运行期从 store 取默认并热切换：</p><table tabindex="0"><thead><tr><th>配置实体</th><th>服务</th><th>关键字段</th><th>默认约束</th></tr></thead><tbody><tr><td><code>SysEmailConfig</code></td><td><code>EmailConfigAppService</code></td><td><code>SmtpHost</code>/<code>SmtpPort</code>/<code>UseSsl</code>/<code>FromEmail</code>/<code>FromName</code>/<code>UserName</code>/<code>Password</code></td><td>每租户单一 <code>IsDefault</code>，<code>Password</code> 经 Data Protection 加密存储、读取永不回显</td></tr><tr><td><code>SysBotConfig</code></td><td><code>BotConfigAppService</code></td><td><code>Provider</code>（<code>DingTalk</code>/<code>Lark</code>/<code>WeCom</code>）/<code>WebhookUrl</code>/<code>Secret</code>/<code>Keyword</code></td><td>每 <code>(TenantId, Provider)</code> 单一 <code>IsDefault</code>，<code>Secret</code> 加密存储</td></tr><tr><td>Telegram</td><td><code>TelegramBotAppService</code></td><td>Token（经 <code>ITelegramBotTokenProtector</code> 保护）</td><td>独立于 Webhook 机器人（长轮询模型），单列成服务</td></tr><tr><td>短信</td><td><code>SmsConfigAppService</code></td><td>服务商 + <code>TemplateMap</code>（内部模板码 → 服务商模板码）</td><td>每租户单一 <code>IsDefault</code>（跨服务商互斥，与邮件同范式；不同于机器人按服务商互斥）</td></tr></tbody></table><p><code>SetDefaultXxxAsync</code> 保证同租户/服务商内默认互斥；配置变更热重载。机器人族的 <code>ChannelBot</code> 与 Webhook 机器人（钉钉加签/飞书签名，企微不用 <code>Secret</code>）由框架 store 在运行时映射为各 Provider 的 Options。</p><hr><h2 id="四、signalr-实时-通知-在线聊天" tabindex="-1">四、SignalR 实时（通知 + 在线聊天） <a class="header-anchor" href="#四、signalr-实时-通知-在线聊天" aria-label="Permalink to &quot;四、SignalR 实时（通知 + 在线聊天）&quot;">​</a></h2><p>实时基于框架 <code>XiHan.Framework.Web.RealTime</code>：Hub 基类 <code>XiHanHub</code>、进程内连接管理 <code>IConnectionManager</code>、泛型 <code>IRealtimeNotificationService&lt;THub&gt;</code>（按用户/用户列表/组/全体推送）。详见 <a href="./../framework/packages/web-realtime">Web.RealTime</a>。BasicApp 侧有两个 Hub。</p><h3 id="通知-hub-basicappnotificationhub" tabindex="-1">通知 Hub（BasicAppNotificationHub） <a class="header-anchor" href="#通知-hub-basicappnotificationhub" aria-label="Permalink to &quot;通知 Hub（BasicAppNotificationHub）&quot;">​</a></h3><p>标注 <code>[AuthorizeHub]</code>。它<strong>不暴露客户端可调方法、也不建组</strong>：仅在连接/断开时刷新用户会话 <code>LastActivityTime</code>（补 HTTP 无状态的活跃度缺口）——在线用户状态 = 活跃会话（DB）+ 实时连接标记（<code>IConnectionManager</code>）。会话刷新失败只记日志，绝不阻断连接生命周期。通知<strong>推送</strong>（<code>ReceiveNotification</code> / <code>TaskProgress</code> / <code>ForceLogout</code> / <code>UserSettingChanged</code> 等，方法名见框架 <code>SignalRConstants.ClientMethods</code>）由服务端 <code>IRealtimeNotificationService&lt;BasicAppNotificationHub&gt;</code> 主动发起。</p><h3 id="聊天-hub-basicappchathub" tabindex="-1">聊天 Hub（BasicAppChatHub） <a class="header-anchor" href="#聊天-hub-basicappchathub" aria-label="Permalink to &quot;聊天 Hub（BasicAppChatHub）&quot;">​</a></h3><p>标注 <code>[AuthorizeHub]</code>。设计上只承载<strong>轻量实时语义</strong>：会话组加入/退出（输入广播边界）与&quot;正在输入&quot;提示（不持久化）。所有<strong>持久化操作</strong>（发消息/撤回/已读）走 <code>ChatAppService</code>（REST），落库后再经 <code>IRealtimeNotificationService&lt;BasicAppChatHub&gt;</code> <strong>按 userId 逐用户</strong>广播（不依赖组，断线重连也不丢消息）。</p><p>Hub 服务端方法（客户端可调）：</p><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Task</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> JoinConversation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> conversationId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 校验成员身份后加入组</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Task</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> LeaveConversation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> conversationId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 退出组</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Task</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Typing</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> conversationId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 向组内其他连接广播 ChatTyping</span></span></code></pre></div><p>组命名：<code>ChatRealtimeMethods.ConversationGroup(id)</code> → <code>chat:conv:{id}</code>。每次 <code>JoinConversation</code> 都校验成员身份（<code>IsMemberAsync</code>），非成员静默拒绝。</p><h3 id="signalr-契约-重要" tabindex="-1">SignalR 契约（重要） <a class="header-anchor" href="#signalr-契约-重要" aria-label="Permalink to &quot;SignalR 契约（重要）&quot;">​</a></h3><ul><li><strong>ID 一律用 <code>string</code></strong>：Hub 方法参数 <code>conversationId</code> 声明为 <code>string</code> 而非 <code>long</code>——雪花 ID 超过 JS <code>number</code> 的 2^53 精度，客户端只能传字符串；Hub 内 <code>TryParse</code> 到 <code>long</code>（<code>&gt; 0</code> 才通过，否则 fail-closed 静默拒绝）。</li><li><strong>无自动转换器</strong>：链路<strong>没有</strong> long→string 或枚举→string 的自动转换器。<strong>载荷需应用侧手动投影</strong>：服务端推送的 payload 是显式构造的匿名对象（如 <code>Typing</code> 的 <code>{ conversationId, userId, userName }</code>、通知的 <code>{ notificationId, notificationType=(int)…, … }</code>），枚举手动转 <code>int</code>、long 手动转 <code>string</code>。</li><li><strong>前端 <code>useSignalR</code> 多实例</strong>：两个 Hub 各建一条连接（各自 <code>useSignalR</code> 实例），互不复用。前端消费时同样需按契约手动投影/解析 payload。</li></ul><p>客户端回调方法名集中在 <code>ChatRealtimeMethods</code>（应用级聊天专用）：</p><table tabindex="0"><thead><tr><th>回调方法</th><th>触发</th><th>载荷要点</th></tr></thead><tbody><tr><td><code>ReceiveChatMessage</code></td><td>新消息</td><td>消息项 + 会话摘要</td></tr><tr><td><code>ChatMessageRecalled</code></td><td>撤回</td><td><code>conversationId</code>, <code>messageId</code></td></tr><tr><td><code>ChatMessageEdited</code></td><td>编辑</td><td><code>conversationId</code>, <code>messageId</code>, <code>content</code>, <code>editedTime</code></td></tr><tr><td><code>ChatReactionChanged</code></td><td>表情回应增删</td><td><code>messageId</code>, <code>emoji</code>, <code>userId</code>, <code>added</code></td></tr><tr><td><code>ChatReadPositionChanged</code></td><td>已读位变更（群已读回执）</td><td><code>conversationId</code>, <code>userId</code>, <code>lastReadMessageId</code></td></tr><tr><td><code>ChatConversationChanged</code></td><td>成员增删/进退群</td><td><code>conversationId</code>, <code>changeType</code>（提示客户端刷新会话列表）</td></tr><tr><td><code>ChatTyping</code></td><td>对端输入中</td><td><code>conversationId</code>, <code>userId</code>, <code>userName</code>（组广播，不持久化）</td></tr></tbody></table><hr><h2 id="五、在线聊天数据模型与能力" tabindex="-1">五、在线聊天数据模型与能力 <a class="header-anchor" href="#五、在线聊天数据模型与能力" aria-label="Permalink to &quot;五、在线聊天数据模型与能力&quot;">​</a></h2><h3 id="数据模型" tabindex="-1">数据模型 <a class="header-anchor" href="#数据模型" aria-label="Permalink to &quot;数据模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>实体</th><th>角色</th><th>关键字段</th></tr></thead><tbody><tr><td><code>SysChatConversation</code></td><td>会话聚合根（单聊/群聊/部门群）</td><td><code>ConversationType</code>（<code>Single</code>/<code>Group</code>/<code>Department</code>）、单聊 <code>PairKey</code>（<code>{小ID}_{大ID}</code> 租户唯一）、群 <code>OwnerUserId</code>、部门群 <code>DepartmentId</code>、冗余 <code>MemberCount</code>/<code>LastMessageId</code>/<code>LastMessageTime</code>/<code>LastMessagePreview</code>、<code>Announcement</code></td></tr><tr><td><code>SysChatConversationMember</code></td><td>成员 × 会话的每人状态</td><td><code>MemberRole</code>（<code>Owner</code>/<code>Admin</code>/<code>Member</code>）、<code>UnreadCount</code>、<code>LastReadMessageId</code>/<code>LastReadTime</code>（已读位）、<code>IsMuted</code>（免打扰）、<code>IsPinned</code>（个人置顶）、<code>IsSilenced</code>（禁言，禁发/禁编辑）</td></tr><tr><td><code>SysChatMessage</code></td><td>单条消息（追加式 + 撤回标记）</td><td><code>MessageType</code>（<code>Text</code>/<code>Image</code>/<code>File</code>/<code>System</code>）、<code>Content</code>、<code>Attachments</code>（JSON <code>{fileId,fileName,fileSize}</code>）、<code>IsRecalled</code>/<code>RecallTime</code>、<code>EditedTime</code>、<code>ReplyToMessageId</code>/<code>ReplyPreview</code>、<code>MentionedUserIds</code>、<code>IsPinned</code>/<code>PinnedByUserId</code>、<code>ClientMessageId</code>（前端生成用于去重/多端对齐）、<code>SenderUserName</code>（发送时快照）</td></tr><tr><td><code>SysChatMessageReaction</code></td><td>消息表情回应（切换语义）</td><td><code>MessageId</code>、<code>UserId</code>、<code>Emoji</code>（Unicode），唯一 <code>(TenantId, MessageId, UserId, Emoji)</code>，取消即删行</td></tr></tbody></table><p>会话三态：<code>Single</code> 用 <code>PairKey</code> 定位（open 即取即建）；<code>Group</code> 有属主与成员治理；<code>Department</code> 随组织结构自动建群。系统消息（<code>MessageType=System</code>，<code>SenderUserId=0</code>）承载进退群/撤回等时间线提示。消息表<strong>只追加 + 撤回打标</strong>，不支持软删（按保留天数清理），也不做按月分表（会破坏按 ID 更新）。</p><h3 id="能力-chatappservice" tabindex="-1">能力（ChatAppService） <a class="header-anchor" href="#能力-chatappservice" aria-label="Permalink to &quot;能力（ChatAppService）&quot;">​</a></h3><p><code>[DynamicApi]</code> 暴露，权限码分三档：<code>Chat.Read</code>（读/个人会话设置）、<code>Chat.Send</code>（发/撤回/编辑/表情/Pin）、<code>Chat.Manage</code>（建群/成员/治理）。持久化走领域服务（UoW），实时推送<strong>尽力而为</strong>、在提交后进行（失败不回滚）。</p><table tabindex="0"><thead><tr><th>分类</th><th>能力</th></tr></thead><tbody><tr><td>会话</td><td>打开单聊 / 部门群、建群、更新群信息（名/公告/头像）、转让群主、个人置顶/免打扰会话（仅推自己，多端同步）</td></tr><tr><td>成员</td><td>加/移成员、设成员角色、设禁言（治理操作自动生成系统消息）</td></tr><tr><td>消息</td><td>发送、<strong>限时撤回（2 分钟内）</strong>、<strong>限时编辑（5 分钟内，仅文本）</strong>、回复（<code>ReplyToMessageId</code> + 预览快照）、@提及（<code>MentionedUserIds</code>，发送时校验，单条上限 20 人）、Pin/Unpin（每会话最多置顶 10 条）、表情回应（切换）、标记已读（广播已读位到全体成员，群已读回执）</td></tr></tbody></table><p><strong>限时窗口</strong>在领域服务 <code>ChatDomainService</code> 中硬编码：撤回窗口 <code>RecallWindowMinutes = 2</code>、编辑窗口 <code>EditWindowMinutes = 5</code>；仅可操作自己发送的消息，已撤回不能编辑，被禁言成员不能发/编辑。</p><h3 id="聊天审计-第四档权限-合规查询" tabindex="-1">聊天审计（第四档权限，合规查询） <a class="header-anchor" href="#聊天审计-第四档权限-合规查询" aria-label="Permalink to &quot;聊天审计（第四档权限，合规查询）&quot;">​</a></h3><p>独立权限码 <code>Chat.Audit</code>（<code>saas:chat:audit</code>），由 <code>ChatAuditQueryService.GetChatMessagePageAsync</code> 承载：管理侧<strong>跨会话</strong>分页查询聊天消息（按会话/发送人/发送时间区间/关键字过滤，关键字匹配正文、发送人名、附件文件名），默认排除已撤回消息（<code>IncludeRecalled</code> 可选纳入），批量带出会话名称/类型免逐行 JOIN。菜单页 <code>/message/chat-audit</code>（<code>message.chat-audit</code>）独立于普通聊天入口，供管理员做内容合规审计，不占用 <code>Chat.Read</code>/<code>Chat.Send</code>/<code>Chat.Manage</code> 三档。</p><p><strong>敏感词拦截</strong>：发送/编辑文本前经 <code>IChatSensitiveWordGuard.EnsureAllowedAsync</code> 校验，命中即 fail-closed 抛业务异常拒绝。词库取自系统设置 <code>SysConfig</code> 键 <code>saas:chat:sensitive-words</code>（全局 <code>TenantId=0</code>，换行/中英文逗号/分号分隔，空=关闭），进程内缓存 60 秒，<code>OrdinalIgnoreCase</code> 包含匹配。</p><hr><h2 id="现状边界-如源码所示" tabindex="-1">现状边界（如源码所示） <a class="header-anchor" href="#现状边界-如源码所示" aria-label="Permalink to &quot;现状边界（如源码所示）&quot;">​</a></h2><ul><li><strong>短信网关</strong>：投递链路、<code>SysSms</code> 记录、<code>SmsConfig</code> + <code>TemplateMap</code> 齐备，但<strong>内置服务商网关适配</strong>依赖外部厂商配置（阿里/腾讯等），需在短信配置登记服务商模板映射；未映射则按纯文本尝试。</li><li><strong>机器人</strong>：Webhook 机器人（钉钉/飞书/企微）与 Telegram 已能作<strong>通知级广播</strong>；<code>ChannelBot</code> 的<strong>按用户定向投递</strong>留作未来能力（当前无用户↔机器人绑定，机器人位只广播）。</li><li><strong>聊天转发</strong>：<code>ChatAppService</code> 未提供&quot;转发&quot;端点，<code>SysChatMessage</code> 也无转发字段——<strong>转发未实现</strong>（当前支持回复而非转发）。</li><li><strong>推送渠道 <code>ChannelPush</code></strong>：偏好里有 <code>Push</code> 开关，但独立的移动/浏览器推送通道未在本模块落地（实时到达仍走 SignalR）。</li><li><strong>站内信&quot;删除消息&quot;</strong>：<code>NotificationStatus.Deleted</code> 状态位已定义、查询侧也已按其过滤，但 <code>UserInboxAppService</code>/<code>UserInboxDomainService</code> 目前没有把消息状态置为 <code>Deleted</code> 的写入端点，也没有对应的物理清理定时任务（不同于日志/聊天消息已有 <code>LogRetentionCleanupTask</code> 按保留期清理）——用户侧删除消息是预留能力，尚未接线。</li><li><strong>偏好类型开关 <code>TypeApproval</code>/<code>TypeMarketing</code></strong>：个人中心可设置，但 <code>NotificationDomainService.FilterByPreferenceAsync</code> 的门控只区分 <code>Security</code>/<code>Todo</code>/其余（落 <code>TypeAnnouncement</code>）三档，这两个开关当前不影响任何通知的送达判定，是面向未来审批/营销类型的预留位。</li></ul><p>以上以仓库源码为准；本页所述字段名/枚举/常量/窗口值均可在对应源码文件核对（<code>modules/XiHan.BasicApp.Saas</code> 下 <code>Domain/Entities</code>、<code>Application/AppServices/Messaging</code>、<code>Application/Services/Messaging</code>、<code>Domain/DomainServices/Messaging</code>、<code>Hubs</code>）。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li>权限码与门控：<a href="./permissions">权限模型</a></li><li>多租户隔离与全局 <code>TenantId=0</code>：<a href="./multi-tenancy">多租户</a></li><li>框架实时通信：<a href="./../framework/packages/web-realtime">Web.RealTime</a></li><li>框架消息路由与发件箱：<a href="./../framework/packages/messaging">Messaging</a></li><li>动态 API 概念：<a href="./../framework/concepts/dynamic-api">dynamic-api</a></li></ul>`,86)])])}const u=o(a,[["render",i]]);export{g as __pageData,u as default};
